{
  "terms": [
    {
      "term": "Generation Methods",
      "simpleDefinition": "The ten specific ways electricity is produced for the UK grid, ranging from burning fuels to using natural forces.",
      "anchor": "The 10 sources: coal, oil, biomass, wind, wave, hydro, nuclear, photovoltaic, gas, and micro-generation.",
      "misconception": "Believing that all electricity is generated in the same type of power station."
    },
    {
      "term": "Transmission Voltages",
      "simpleDefinition": "The three specific high-pressure levels used to move bulk electricity over long distances across the country.",
      "anchor": "The three levels: 400 kV, 275 kV, and 132 kV.",
      "misconception": "Confusing these high transmission voltages with the lower distribution voltages used in streets and homes."
    },
    {
      "term": "Kilovolt (kV)",
      "simpleDefinition": "A unit of electrical pressure equal to 1,000 Volts.",
      "anchor": "1 kV = 1,000 V.",
      "misconception": "Underestimating the scale of transmission by forgetting that 'k' means multiply by a thousand."
    },
    {
      "term": "Transmission",
      "simpleDefinition": "The 'super-highway' stage of the supply chain where electricity travels from power stations to the local network.",
      "anchor": "Bulk movement of energy at very high voltages to reduce losses.",
      "misconception": "Thinking transmission refers to the cables in your house; it actually refers to the large pylons and cross-country lines."
    },
    {
      "term": "Micro-generation",
      "simpleDefinition": "Small-scale production of electricity, usually by individual homeowners or small businesses.",
      "anchor": "Domestic solar panels or small-scale wind turbines.",
      "misconception": "Assuming all electricity must come from a massive central power station."
    },
    {
      "term": "Photovoltaic (PV)",
      "simpleDefinition": "A method of generating electricity directly from sunlight using solar cells.",
      "anchor": "Solar panels.",
      "misconception": "Thinking solar panels only work in hot weather; they actually only need light, not heat."
    }
  ],
  "anchorPhrases": [
    "The 132, 275, 400 rule for transmission.",
    "1,000 Volts in every Kilovolt.",
    "The 10 methods of generation.",
    "High voltage for long distance."
  ],
  "misconceptionTargets": [
    "Mixing up 132 kV (transmission) with 33 kV or 11 kV (distribution).",
    "Thinking 400V (three-phase) is a transmission voltage.",
    "Believing micro-generation is only for off-grid use.",
    "Using the terms 'transmission' and 'distribution' interchangeably."
  ]
}

{
  "teachChecks": [
    {
      "key": "203-5a-teach-check-1",
      "title": "Generation Methods",
      "objective": "Identify the ten primary generation methods used for electricity distribution.",
      "retrievalTextLines": [
        "Electricity generation is the starting point of the electrical supply chain. To provide power to the national grid, ten specific methods are recognized in the UK. These include fossil fuels like coal, oil, and gas, as well as nuclear power. We also use biomass, which involves burning organic materials. Renewable energy is captured through wind, wave, and hydro (water) power. Sunlight is converted into electricity using photovoltaic (PV) cells, often seen as solar panels. While most generation happens at large power stations, we also include micro-generation. Micro-generation refers to small-scale production, such as solar panels on a house roof or a small wind turbine for a single building. Every one of these ten methods serves the same purpose: creating the initial electrical energy that will eventually reach the consumer."
      ],
      "hint": "Think of the three fossil fuels, the three water/wind forces, nuclear, biomass, solar panels, and small-scale home systems."
    },
    {
      "key": "203-5a-teach-check-2",
      "title": "Transmission Voltages",
      "objective": "Identify the three specific high-voltage levels used for the UK transmission grid.",
      "retrievalTextLines": [
        "After electricity is generated, it enters the transmission stage. Transmission is the 'super-highway' of the grid, moving bulk electricity over long distances across the country. To do this efficiently, we use very high voltages. The reason for using high voltage is to reduce energy loss; higher pressure allows the same amount of power to be moved with less current, which prevents the cables from wasting energy as heat. In the UK, there are three specific transmission voltages: 400 kV, 275 kV, and 132 kV. The abbreviation 'kV' stands for Kilovolt. Since 'kilo' means one thousand, 1 kV is equal to 1,000 Volts. This means 132 kV is actually 132,000 Volts. It is vital to distinguish these high transmission levels from the lower voltages used in local streets, which are part of the distribution network."
      ],
      "hint": "The three transmission voltages are all measured in kV (thousands of volts) and start at 132."
    }
  ]
}

